1	/// Integration tests for the RuntimeCommand channel contract.
2	///
3	/// These tests exercise the coordinator drain logic, DaemonHandle channel
4	/// forwarding, and the Dispatcher threshold update path end-to-end without
5	/// spinning up a full audio pipeline.
6	use std::sync::{mpsc, Arc};
7	use vibe_attack::control::protocol::ActivationMode;
8	use vibe_attack::pipeline::coordinator::RuntimeCommand;
9	use vibe_attack::pipeline::dispatcher::{DispatchOutcome, Dispatcher};
10	
11	fn make_dispatcher(threshold: f32, phrase: &str) -> Arc<Dispatcher> {
12	    use vibe_attack::config::MacroConfig;
13	    let (tx, _rx) = mpsc::channel();
14	    let macro_cfg = MacroConfig {
15	        name: "test_macro".to_string(),
16	        phrase: Some(phrase.to_string()),
17	        if_flag: None,
18	        set_flag: None,
19	        sound: None,
20	        keys: vec![],
21	    };
22	    Arc::new(Dispatcher::new(threshold, vec![macro_cfg], tx, 50, 30))
23	}
24	
25	// ── Channel drain simulation ─────────────────────────────────────────────────
26	
27	/// Simulates the coordinator's per-frame try_recv drain against a Dispatcher.
28	/// Returns the number of commands processed.
29	fn drain_into_dispatcher(rx: &mpsc::Receiver<RuntimeCommand>, dispatcher: &Arc<Dispatcher>) -> usize {
30	    let mut count = 0;
31	    while let Ok(cmd) = rx.try_recv() {
32	        match cmd {
33	            RuntimeCommand::SetThreshold(t) => {
34	                dispatcher.update_threshold(t);
35	                count += 1;
36	            }
37	            RuntimeCommand::SetMode(_m) => {
38	                count += 1;
39	            }
40	            RuntimeCommand::SetInputDevice(_) | RuntimeCommand::SetPttBinding(_) | RuntimeCommand::ReloadConfig => {
41	                count += 1;
42	            }
43	        }
44	    }
45	    count
46	}
47	
48	// ── Happy-path tests ─────────────────────────────────────────────────────────
49	
50	#[test]
51	fn set_threshold_via_channel_changes_dispatch_outcome() {
52	    // Start with a threshold so high nothing matches.
53	    let dispatcher = make_dispatcher(0.99, "eagle airstrike");
54	    let (tx, rx) = mpsc::channel::<RuntimeCommand>();
55	
56	    // Confirm NoMatch at strict threshold.
57	    assert!(
58	        matches!(dispatcher.process("eagal airstrike"), DispatchOutcome::NoMatch),
59	        "expected NoMatch before threshold update"
60	    );
61	
62	    // Send SetThreshold over the channel, then drain it into the dispatcher.
63	    tx.send(RuntimeCommand::SetThreshold(0.5)).unwrap();
64	    let processed = drain_into_dispatcher(&rx, &dispatcher);
65	    assert_eq!(processed, 1, "expected exactly one command drained");
66	
67	    // After threshold update the same near-miss phrase should fire.
68	    assert!(
69	        matches!(dispatcher.process("eagal airstrike"), DispatchOutcome::Fired { .. }),
70	        "expected Fired after threshold lowered via channel"
71	    );
72	}
73	
74	#[test]
75	fn set_threshold_clamp_via_channel() {
76	    let dispatcher = make_dispatcher(0.5, "eagle airstrike");
77	    let (tx, rx) = mpsc::channel::<RuntimeCommand>();
78	
79	    // Send an out-of-range value — update_threshold clamps it internally.
80	    tx.send(RuntimeCommand::SetThreshold(1.5)).unwrap();
81	    drain_into_dispatcher(&rx, &dispatcher);
82	
83	    // Clamped to 1.0 → near-miss should not match.
84	    assert!(
85	        matches!(dispatcher.process("eagal airstrike"), DispatchOutcome::NoMatch),
86	        "expected NoMatch after threshold clamped to 1.0"
87	    );
88	    // Exact match should still fire (score == 1.0 >= 1.0).
89	    assert!(
90	        matches!(dispatcher.process("eagle airstrike"), DispatchOutcome::Fired { .. }),
91	        "expected Fired on exact match after clamp"
92	    );
93	}
