95	#[test]
96	fn set_mode_command_is_accepted_by_drain() {
97	    let dispatcher = make_dispatcher(0.5, "eagle airstrike");
98	    let (tx, rx) = mpsc::channel::<RuntimeCommand>();
99	
100	    tx.send(RuntimeCommand::SetMode(ActivationMode::Wake)).unwrap();
101	    let processed = drain_into_dispatcher(&rx, &dispatcher);
102	    assert_eq!(processed, 1);
103	
104	    tx.send(RuntimeCommand::SetMode(ActivationMode::Ptt)).unwrap();
105	    let processed = drain_into_dispatcher(&rx, &dispatcher);
106	    assert_eq!(processed, 1);
