111	/// When the Receiver is dropped (coordinator gone), the Sender returns SendError.
112	/// The control handler converts this to ControlResponse::Error{message}.
113	#[test]
114	fn channel_send_after_receiver_dropped_returns_error() {
115	    let (tx, rx) = mpsc::channel::<RuntimeCommand>();
116	    drop(rx); // simulate coordinator stopped
