122	/// DaemonHandle with no runtime_tx attached returns pipeline-not-running error.
123	#[test]
124	fn daemon_handle_without_runtime_tx_returns_error() {
125	    use vibe_attack::control::{protocol::ControlResponse, DaemonHandle};
126	
127	    let (macro_tx, _macro_rx) = mpsc::channel();
128	    let dispatcher = Arc::new(Dispatcher::new(0.5, vec![], macro_tx, 50, 30));
129	    let handle = DaemonHandle::new(dispatcher); // no runtime_tx attached
130	
131	    // Access via the internal send helper through control protocol test.
132	    // We verify indirectly: runtime_cmd_tx is None, so any forwarded command
133	    // should produce ControlResponse::Error{message}.
134	    let result = match &handle.runtime_cmd_tx {
135	        None => ControlResponse::Error { message: "pipeline not running".into() },
136	        Some(tx) => match tx.send(RuntimeCommand::SetThreshold(0.5)) {
137	            Ok(()) => ControlResponse::Ok,
138	            Err(_) => ControlResponse::Error { message: "pipeline not running".into() },
139	        },
140	    };
141	    assert!(
142	        matches!(result, ControlResponse::Error { ref message } if message == "pipeline not running"),
143	        "expected pipeline-not-running error, got: {result:?}"
144	    );
145	}
