147	/// Multiple commands queued before drain are all processed in order.
148	#[test]
149	fn multiple_commands_drained_in_order() {
150	    let dispatcher = make_dispatcher(0.99, "eagle airstrike");
151	    let (tx, rx) = mpsc::channel::<RuntimeCommand>();
152	
153	    tx.send(RuntimeCommand::SetThreshold(0.99)).unwrap();
154	    tx.send(RuntimeCommand::SetThreshold(0.5)).unwrap();
155	
156	    let processed = drain_into_dispatcher(&rx, &dispatcher);
157	    assert_eq!(processed, 2);
158	
159	    // Last command (0.5) wins — near-miss fires.
160	    assert!(
161	        matches!(dispatcher.process("eagal airstrike"), DispatchOutcome::Fired { .. }),
162	        "expected Fired — last SetThreshold(0.5) should win"
163	    );
164	}
