60	#[test]
61	fn daemon_exits_with_error_on_missing_config() {
62	    let bin = daemon_bin();
63	    if !bin.exists() {
64	        eprintln!("Daemon binary not found, skipping");
65	        return;
66	    }
67	
68	    let output = Command::new(&bin)
69	        .arg("--config")
70	        .arg("/tmp/vibe_attack_nonexistent_config_xyz.yaml")
71	        .env_remove("WAYLAND_DISPLAY")
72	        .env_remove("DISPLAY")
73	        .output()
74	        .expect("Failed to spawn daemon");
75	
76	    assert!(
