81	    let stderr = String::from_utf8_lossy(&output.stderr);
82	    assert!(
83	        stderr.contains("not found")
84	            || stderr.contains("No such file")
85	            || stderr.contains("Config")
86	            || stderr.contains("os error"),
87	        "Stderr must mention config error, got: {stderr}"
88	    );
89	
90	    assert!(
91	        !stderr.contains("wayland") && !stderr.contains("DISPLAY"),
92	        "Daemon must not attempt display server connection on startup, got: {stderr}"
93	    );
94	}
